import{_ as s,I as n,o as d,c as h,at as p,j as e,a as r,J as t,w as c}from"./chunks/framework.DYZFTu11.js";const N=JSON.parse('{"title":"诅咒之地 · 地理与历史","description":"","frontmatter":{},"headers":[],"relativePath":"zh_cn/locations/cursed-land.md","filePath":"zh_cn/locations/cursed-land.md","lastUpdated":1774091102000}'),b={name:"zh_cn/locations/cursed-land.md"};function m(f,a,u,P,_,x){const l=n("VPNolebaseInlineLinkPreview"),o=n("NolebaseGitContributors"),i=n("NolebaseGitChangelog");return d(),h("div",null,[a[3]||(a[3]=p('<h1 id="诅咒之地-·-地理与历史" tabindex="-1">诅咒之地 · 地理与历史 <a class="header-anchor" href="#诅咒之地-·-地理与历史" aria-label="Permalink to “诅咒之地 · 地理与历史”">​</a></h1><h2 id="地理特征" tabindex="-1">地理特征 <a class="header-anchor" href="#地理特征" aria-label="Permalink to “地理特征”">​</a></h2><p>诅咒之地位于α星赤道附近，是一片面积约占星球表面15%的广袤区域。该地带展现出α星最极端的自然环境特征，已成为行星学者与地质学家重点研究对象。</p><h3 id="大气与气候" tabindex="-1">大气与气候 <a class="header-anchor" href="#大气与气候" aria-label="Permalink to “大气与气候”">​</a></h3><p>该地区大气成分异常，长期侦测数据显示存在高浓度的异常粒子。这些粒子对电磁波产生强烈干扰，导致该区域呈现出独特的视觉特征——天空长年呈现深紫色调，此现象由高空离子对太阳光的折射与吸收所致。</p><p>诅咒之地内部磁场异常强烈，磁场强度变化幅度远超α星其他地区。磁暴现象频繁，导致该区域的通讯信号极度不稳定。根据财团气象部门的记录，该地区频繁发生局部高能粒子风暴，伴随高能电光放电现象。这些放电呈现出蓝紫色，且通常不伴随可听觉的雷鸣，表明其放电机制不同于典型的大气静电放电。</p><h3 id="地表地貌" tabindex="-1">地表地貌 <a class="header-anchor" href="#地表地貌" aria-label="Permalink to “地表地貌”">​</a></h3><p>诅咒之地的地表被密集的裂隙系统所支配，形成了一个复杂的分割地貌。这些裂隙深度不一，从数米到数百米不等。最大的裂隙带宽度超过两公里，足以吞没城镇规模的设施。</p><p>根据地质测量数据，这些裂隙的分布并非随机，而是遵循特定的几何规律。它们形成了一个复杂的线性与环形网络，从高空俯瞰能观察到明显的规则性图案。有学者推测，这一规律性分布可能源于地下深处的异常能量或应力场的作用。</p><p>地表大部分区域被灰白色至浅紫色的风化物质覆盖，其成分与α星其他地区的岩石构成明显不同。该物质具有极低的含水量与极高的脆性，风化速度远超正常预期，这表明该地区经历了某种加速的化学或物理过程。</p><p>裂隙内部呈现出不透光的深色，该现象由沉积物的特殊光学性质所致，导致光线吸收效率极高。</p><h2 id="生物学现象" tabindex="-1">生物学现象 <a class="header-anchor" href="#生物学现象" aria-label="Permalink to “生物学现象”">​</a></h2><p>该地区完全缺乏已知的地表生态系统。长期的科学考察未发现任何植被或可移动的宏观生物。该现象与地表环境的极端性质直接相关——高能辐射、磁场异常与化学成分不适合已知的碳基生命形式存活。</p><p>然而，出土的地层样本显示过去存在过有机质痕迹，表明该区域在地质历史的某个时期可能支撑过生命活动。当前的无生命状态可能源于近期的某种剧烈事件。</p><h2 id="人类设施" tabindex="-1">人类设施 <a class="header-anchor" href="#人类设施" aria-label="Permalink to “人类设施”">​</a></h2><h3 id="防卫前哨系统" tabindex="-1">防卫前哨系统 <a class="header-anchor" href="#防卫前哨系统" aria-label="Permalink to “防卫前哨系统”">​</a></h3><p>财团在诅咒之地周边部署了一系列侦测与防卫设施，其中最著名的是代号为&quot;壁虎&quot;的临时哨站。该哨站位于周边为数不多的高地之一，地理位置优越。根据军方记录，该哨站的主要功能是监测诅咒之地的能量异常波动与灵裔活动迹象。</p><p>该区域通讯设备长期处于严重故障状态，人员补给依赖不稳定的空中投送。历史记录表明，补给线的中断事件曾导致预置人员的严重损失。</p><h3 id="秘密研究设施" tabindex="-1">秘密研究设施 <a class="header-anchor" href="#秘密研究设施" aria-label="Permalink to “秘密研究设施”">​</a></h3><p>财团在诅咒之地周边部署了优先级最高的研究所，该设施外观采用了复杂的几何隐匿设计，建筑主体半埋入地表。设施规模庞大，包含多层地下空间。</p><p>根据残留的财团档案，该设施的建筑设计采用了非欧几里得拓扑原理。走廊设计刻意导入空间混乱，使得物理距离与实际行走距离不相符。设计者声称此举是为了对抗未知的精神干涉能力，但实际效果如何仍存疑。</p><p>深层实验室区域的照明系统工作在非自然频率，长期暴露于此环境已被证实会导致人体的认知功能障碍。根据职业健康报告，在该区域工作超过两年的研究人员中有大比例因&quot;心理不适&quot;被强制调离。</p><h2 id="灵裔与财团的关系" tabindex="-1">灵裔与财团的关系 <a class="header-anchor" href="#灵裔与财团的关系" aria-label="Permalink to “灵裔与财团的关系”">​</a></h2><h3 id="生物学试验痕迹" tabindex="-1">生物学试验痕迹 <a class="header-anchor" href="#生物学试验痕迹" aria-label="Permalink to “生物学试验痕迹”">​</a></h3><p>诅咒之地的研究设施内发现了大量的生物培养装置，学术界称之为&quot;孵化舱&quot;。这些装置为密闭容器，内部充满某种发光的液体培养基。根据设备规格，孵化舱直径可达数米，高度超过三十米。</p><p>舱内发现了多种形态的生物样本。其中一些具有类人形态，但皮肤结构与色素沉着不符合标准人类特征。某些样本的皮肤呈现出蓝紫色或金属色质感。其他样本则呈现出更为异质的形态——由膜状组织与流体构成，内部流动着荧光物质。</p><p>这些容器内的生物似乎具有某种定向感知能力，容器外来的物体接近时它们会改变位置或姿态。该现象表明这些生物可能具有高级的神经感受系统。</p><h3 id="符号系统" tabindex="-1">符号系统 <a class="header-anchor" href="#符号系统" aria-label="Permalink to “符号系统”">​</a></h3><p>孵化舱及其周围的设施壁面被密集地刻上了某种规则的标记符号。这些符号与诅咒之地地表裂隙形成的图案在外形上完全相同，表明可能存在某种关联性。符号的刻画深度不一，浅处如同长期抓挠的痕迹，深处则几乎穿透三厘米厚的合金板。</p><p>符号的几何结构与已知的任何人类或灵裔文字系统都不相符。破译尝试均以失败告终。</p><h2 id="_2062年事件后的变化" tabindex="-1">2062年事件后的变化 <a class="header-anchor" href="#_2062年事件后的变化" aria-label="Permalink to “2062年事件后的变化”">​</a></h2>',31)),e("p",null,[a[1]||(a[1]=r("灵裔占领诅咒之地（参见",-1)),t(l,{href:"./../events/alpha-star-massacre"},{default:c(()=>[...a[0]||(a[0]=[r("α星大屠杀",-1)])]),_:1}),a[2]||(a[2]=r("）后，该地区进入了一个观测困难的阶段。财团对该地区的直接考察已完全停止，现状主要依赖于无人卫星遥感数据推断。",-1))]),a[4]||(a[4]=e("h3",{id:"设施状态",tabindex:"-1"},[r("设施状态 "),e("a",{class:"header-anchor",href:"#设施状态","aria-label":"Permalink to “设施状态”"},"​")],-1)),a[5]||(a[5]=e("p",null,"研究所的大部分设施已被灵裔接管或破坏。剩余的孵化舱中，生物样本已大规模撤离。仅有少数舱仍保有内容物，其中培养液颜色已发生改变，从之前的无色发光变成深紫色不透明液体。容器壁上的震颤信号表明内部仍有活动的生命体。",-1)),a[6]||(a[6]=e("p",null,[e("em",null,"诅咒之地的当前状况及其变化趋势持续被学术界与战略分析机构关注。")],-1)),t(o),t(i)])}const C=s(b,[["render",m]]);export{N as __pageData,C as default};
